 1	import React from 'react';
 2	
 3	import { documentationURL } from '@kubevirt-utils/constants/documentation';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { Button, Stack, StackItem } from '@patternfly/react-core';
 6	import { ExternalLinkSquareAltIcon } from '@patternfly/react-icons';
 7	
 8	const CloudInitInfoHelper = () => {
 9	  const { t } = useKubevirtTranslation();
10	  return (
11	    <Stack className="kv-cloudinit-info-helper--main">
12	      <StackItem>
13	        {t(
14	          'You can use cloud-init to initialize the operating system with a specific configuration when the VirtualMachine is started.',
15	        )}
16	      </StackItem>
17	      <StackItem>
18	        <div className="text-muted">
19	          {t('The cloud-init service is enabled by default in Fedora and RHEL images.')}{' '}
20	          <Button
21	            icon={<ExternalLinkSquareAltIcon />}
22	            iconPosition="right"
23	            isInline
24	            size="sm"
25	            variant="link"
26	          >
27	            <a href={documentationURL.CLOUDINIT_INFO} rel="noopener noreferrer" target="_blank">
28	              {t('Learn more')}
29	            </a>
30	          </Button>
31	        </div>
32	      </StackItem>
33	    </Stack>
34	  );
35	};
36	
37	export default CloudInitInfoHelper;

